"use client";

import Link from "next/link";
import type { AdminDashboardData } from "@/lib/admin-dashboard";

const NAVY = "#1E3A5F";
const CARD_BORDER = "rgba(210,210,215,0.2)";
const ROW_BORDER = "rgba(210,210,215,0.1)";
const INK = "#1D1D1F";
const INK_50 = "rgba(29,29,31,0.5)";
const INK_40 = "rgba(29,29,31,0.4)";
const INK_30 = "rgba(29,29,31,0.3)";

const KPI_ICONS = [<KpiMoneyIcon key="m" />, <KpiUserPlusIcon key="u" />, <KpiUserIcon key="d" />, <KpiGroupIcon key="g" />];

const TABLE_GRID = "minmax(0,245.9px) minmax(0,255.9px) minmax(0,1fr) 182.5px";

export function DashboardView({ data }: { data: AdminDashboardData }) {
  return (
    <div style={{ width: "100%" }}>
      <div style={{ paddingBottom: "34.16px" }}>
        <h1 style={{ margin: 0, fontSize: "18px", fontWeight: 700, letterSpacing: "-0.504px", lineHeight: "22.5px", color: INK }}>
          관제 센터
        </h1>
        <p style={{ margin: "2.44px 0 0", fontSize: "12px", fontWeight: 400, letterSpacing: "-0.18px", lineHeight: "21.6px", color: INK_40 }}>
          KORLINK 플랫폼 종합 운영 현황
        </p>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, minmax(0,1fr))", gap: "14.64px", paddingBottom: "34.16px" }}>
        {data.kpis.map((k, i) => (
          <div
            key={k.label}
            style={{
              background: "#fff",
              borderRadius: "14.64px",
              border: `1px solid ${CARD_BORDER}`,
              padding: "20.52px",
            }}
          >
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", paddingBottom: "14.64px" }}>
              <span style={{ fontSize: "11px", fontWeight: 500, letterSpacing: "-0.165px", lineHeight: "19.8px", color: INK_40 }}>{k.label}</span>
              {KPI_ICONS[i]}
            </div>
            <p style={{ margin: 0, fontSize: "22px", fontWeight: 700, letterSpacing: "-0.33px", lineHeight: "22px", color: INK }}>{k.value}</p>
          </div>
        ))}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "24.4px", paddingBottom: "24.4px" }}>
        <section style={{ background: "#fff", borderRadius: "14.64px", border: `1px solid ${CARD_BORDER}`, overflow: "hidden" }}>
          <div style={{ padding: "17.08px 24.4px 18.08px" }}>
            <p style={{ margin: 0, fontSize: "13px", fontWeight: 700, letterSpacing: "-0.364px", lineHeight: "16.25px", color: INK }}>
              비교견적 프로세스 현황
            </p>
          </div>
          <div>
            {data.stages.map((s, i) => (
              <div
                key={s.label}
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  padding: i === 0 ? "14.64px 24.4px" : "15.64px 24.4px 14.64px",
                  borderTop: i === 0 ? "none" : `1px solid ${ROW_BORDER}`,
                }}
              >
                <span
                  style={{
                    display: "inline-flex",
                    alignItems: "center",
                    justifyContent: "center",
                    borderRadius: "9999px",
                    padding: "4.88px 12.2px",
                    fontSize: "11px",
                    fontWeight: 600,
                    letterSpacing: "-0.165px",
                    lineHeight: "19.8px",
                    background: s.bg,
                    color: s.color,
                  }}
                >
                  {s.label}
                </span>
                <span style={{ display: "flex", alignItems: "baseline", gap: "4px" }}>
                  <span style={{ fontSize: "18px", fontWeight: 700, letterSpacing: "-0.27px", lineHeight: "32.4px", color: INK }}>{s.count}</span>
                  <span style={{ fontSize: "11px", fontWeight: 400, letterSpacing: "-0.165px", lineHeight: "19.8px", color: INK_30 }}>건</span>
                </span>
              </div>
            ))}
          </div>
        </section>

        <section style={{ background: "#fff", borderRadius: "14.64px", border: `1px solid ${CARD_BORDER}`, overflow: "hidden" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "17.08px 24.4px 18.08px" }}>
            <p style={{ margin: 0, fontSize: "13px", fontWeight: 700, letterSpacing: "-0.364px", lineHeight: "16.25px", color: INK }}>
              최근 비교견적 요청
            </p>
            <Link href="/admin/contents" style={{ display: "inline-flex", alignItems: "center", gap: "2px", fontSize: "11px", fontWeight: 500, letterSpacing: "-0.293px", lineHeight: "19.25px", color: INK_40, textDecoration: "none" }}>
              전체 보기 <ArrowIcon />
            </Link>
          </div>
          <div>
            {data.recentRequests.map((r, i) => (
              <div
                key={r.title}
                style={{
                  padding: i === 0 ? "14.64px 24.4px" : "15.64px 24.4px 14.64px",
                  borderTop: i === 0 ? "none" : `1px solid ${ROW_BORDER}`,
                }}
              >
                <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: "12px", paddingBottom: "4.88px" }}>
                  <span
                    style={{
                      fontSize: "13px",
                      fontWeight: 500,
                      letterSpacing: "-0.195px",
                      lineHeight: "23.4px",
                      color: INK,
                      minWidth: 0,
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                      whiteSpace: "nowrap",
                    }}
                  >
                    {r.title}
                  </span>
                  <span style={{ flexShrink: 0, fontSize: "11px", fontWeight: 400, letterSpacing: "-0.165px", lineHeight: "19.8px", color: INK_30 }}>{r.date}</span>
                </div>
                <p style={{ margin: 0, fontSize: "11px", fontWeight: 400, letterSpacing: "-0.165px", lineHeight: "19.8px", color: INK_40 }}>{r.meta}</p>
              </div>
            ))}
          </div>
        </section>
      </div>

      <section style={{ background: "#fff", borderRadius: "14.64px", border: `1px solid ${CARD_BORDER}`, overflow: "hidden" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "17.08px 24.4px 18.08px" }}>
          <p style={{ margin: 0, fontSize: "13px", fontWeight: 700, letterSpacing: "-0.364px", lineHeight: "16.25px", color: INK }}>
            입점 신청 현황
          </p>
          <Link href="/admin/approval" style={{ display: "inline-flex", alignItems: "center", gap: "2px", fontSize: "11px", fontWeight: 500, letterSpacing: "-0.293px", lineHeight: "19.25px", color: INK_40, textDecoration: "none" }}>
            전체보기 <ArrowIcon />
          </Link>
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: TABLE_GRID,
            alignItems: "center",
            background: "rgba(29,29,31,0.02)",
            borderTop: `1px solid ${ROW_BORDER}`,
            borderBottom: `1px solid ${ROW_BORDER}`,
          }}
        >
          {["업체명", "사업자번호", "카테고리", "상태"].map((h) => (
            <span key={h} style={{ padding: "14.64px 24.4px", fontSize: "11px", fontWeight: 600, letterSpacing: "-0.165px", lineHeight: "19.8px", color: INK_40 }}>
              {h}
            </span>
          ))}
        </div>
        {data.applicants.map((a, i) => (
          <div
            key={a.id}
            style={{
              display: "grid",
              gridTemplateColumns: TABLE_GRID,
              alignItems: "center",
              borderTop: i === 0 ? "none" : `1px solid ${ROW_BORDER}`,
            }}
          >
            <span style={{ padding: "14.64px 24.4px", fontSize: "13px", fontWeight: 500, letterSpacing: "-0.195px", lineHeight: "23.4px", color: INK }}>{a.name}</span>
            <span style={{ padding: "14.64px 24.4px", fontSize: "12px", fontWeight: 400, letterSpacing: "-0.18px", lineHeight: "21.6px", color: INK_50 }}>{a.biz}</span>
            <span style={{ padding: "14.64px 24.4px", fontSize: "12px", fontWeight: 400, letterSpacing: "-0.18px", lineHeight: "21.6px", color: INK_50 }}>{a.category}</span>
            <span style={{ padding: "14.64px 24.4px" }}>
              <span
                style={{
                  display: "inline-flex",
                  alignItems: "center",
                  justifyContent: "center",
                  borderRadius: "9999px",
                  height: "25px",
                  padding: "0 13.2px",
                  fontSize: "11px",
                  fontWeight: 500,
                  letterSpacing: "-0.165px",
                  lineHeight: "19.8px",
                  background: "#FFFBEB",
                  border: "1px solid #FDE68A",
                  color: "#D97706",
                }}
              >
                대기
              </span>
            </span>
          </div>
        ))}
      </section>
    </div>
  );
}

